    VMOVDQU64 64(DI), Z12      // b[64:128]
    VPSADBW Z12, Z11, Z15
    VPADDQ Z15, Z3, Z3
    VPMAXUB Z12, Z11, Z13
    VPMINUB Z12, Z11, Z14
    VPSUBB Z14, Z13, Z13
    VPXORD Z4, Z13, Z14
    VPDPBUSD Z14, Z13, Z1
    ADDQ $128, SI
    ADDQ $128, DI
    DECQ CX
    JNZ lv512_loop128

lv512_tail64:
    TESTQ $64, DX
    JZ lv512_tail_scalar
    VMOVDQU64 (SI), Z6
    VMOVDQU64 (DI), Z7
    VPSADBW Z7, Z6, Z10
    VPADDQ Z10, Z2, Z2
    VPMAXUB Z7, Z6, Z8
    VPMINUB Z7, Z6, Z9
    VPSUBB Z9, Z8, Z8
    VPXORD Z4, Z8, Z9
    VPDPBUSD Z9, Z8, Z0
