    ADDQ $64, DI

lv512_tail_scalar:
    MOVQ DX, CX
    ANDQ $63, CX
    JZ lv512_reduce

lv512_scalar:
    MOVBLZX (SI), R9
    MOVBLZX (DI), R10
    SUBL R10, R9
    IMULL R9, R9
    ADDL R9, BX
    INCQ SI
    INCQ DI
    DECQ CX
    JNZ lv512_scalar

lv512_reduce:
    VPADDD Z1, Z0, Z0
    VPADDQ Z3, Z2, Z2
    VEXTRACTI64X4 $1, Z0, Y1
    VPADDD Y1, Y0, Y0
    VEXTRACTI128 $1, Y0, X1
    VPADDD X1, X0, X0
    VPSHUFD $0x4E, X0, X1
    VPADDD X1, X0, X0
    VPSHUFD $0xB1, X0, X1
    VPADDD X1, X0, X0
    VMOVD X0, AX
    VEXTRACTI64X4 $1, Z2, Y3
    VPADDQ Y3, Y2, Y2
    VEXTRACTI128 $1, Y2, X3
    VPADDQ X3, X2, X2
    VPSHUFD $0x4E, X2, X3
    VPADDQ X3, X2, X2
    VMOVD X2, R9
    SHLL $7, R9                // 128 * sum |a-b|
